 1	import { type FC, useMemo } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
 5	import Select from '@components/common/Select';
 6	import { FormGroup } from '@patternfly/react-core';
 7	import { useForkliftTranslation } from '@utils/i18n';
 8	
 9	import { StorageMapFieldId, storageMapFieldLabels } from '../../constants';
10	import { useStorageVendorProducts } from '../../hooks/useStorageVendorProducts';
11	import { getVendorProductLabel } from '../../utils/labelHelpers';
12	
13	type StorageProductFieldProps = { fieldId: string };
14	
15	const StorageProductField: FC<StorageProductFieldProps> = ({ fieldId }) => {
16	  const { t } = useForkliftTranslation();
17	  const {
18	    control,
19	    formState: { isSubmitting },
20	  } = useFormContext();
21	  const { loading, storageVendorProducts } = useStorageVendorProducts();
22	
23	  const options = useMemo(
24	    () =>
25	      storageVendorProducts.map((product) => ({
26	        label: getVendorProductLabel(product),
27	        value: product,
28	      })),
29	    [storageVendorProducts],
30	  );
31	
32	  return (
33	    <FormGroup
34	      fieldId={fieldId}
35	      label={storageMapFieldLabels[StorageMapFieldId.StorageProduct]}
36	      labelHelp={
37	        <HelpIconPopover>
38	          {t(
39	            'The commercial product name or model of the storage system being used. This helps ensure the correct features and APIs will be used.',
40	          )}
41	        </HelpIconPopover>
42	      }
43	    >
44	      <Controller
45	        name={fieldId}
46	        control={control}
47	        render={({ field }) => (
48	          <Select
49	            ref={field.ref}
50	            id={fieldId}
51	            isDisabled={isSubmitting || loading}
52	            value={field.value}
53	            options={options}
54	            onSelect={(_event, value) => {
55	              field.onChange(value);
56	            }}
57	            placeholder={t('Select storage product')}
58	          />
59	        )}
60	      />
61	    </FormGroup>
62	  );
63	};
64	
65	export default StorageProductField;

